mapper.select:
SELECT
    id, spu_id, sku_id, level_id, image_url, image_type, sort_order, is_primary,
    status, deleted, created_at, updated_at, created_by, updated_by
FROM item_image
WHERE deleted = 0

    AND spu_id = #{spuId}


    AND sku_id = #{skuId}


    AND level_id = #{levelId}


    AND status = #{status}

ORDER BY sort_order ASC, id ASC
